class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

def isValidBST(root: TreeNode) -> bool:
    def _isValidBST_helper(node, lower=None, upper=None) -> bool:
        if not node:
            return True

        if lower is not None and node.val <= lower:
            return False
        if upper is not None and node.val >= upper:
            return False

        if not _isValidBST_helper(node.left, lower, node.val):
            return False
        if not _isValidBST_helper(node.right, node.val, upper):
            return False

        return True

    return _isValidBST_helper(root)
